:root {
  --card-bg: #ffffff;
  --card-border: #e8e0d5;
  --card-radius: 16px;
  --header-bg: #2d1b0e;
  --category-color: #f5c97a;
  --vegan-bg: #4a7c59;
  --vegan-text: #ffffff;
  --item-name-color: #1a1008;
  --desc-color: #6b5744;
  --meta-pill-bg: #f4ede4;
  --meta-pill-color: #7a5c44;
  --image-bg: #e8ddd0;
  --image-accent: #c4a882;
  --price-color: #2d1b0e;
  --btn-bg: #c0392b;
  --btn-text: #ffffff;
  --btn-radius: 8px;
  --footer-bg: #faf6f1;
  --footer-border: #e8e0d5;
  --footer-label-color: #a0856c;
  --chip-bg: #ede4d8;
  --chip-color: #6b4f37;
}

.menu-card {
  background: var(--card-bg);
  border: 1.5px solid var(--card-border);
  border-radius: var(--card-radius);
  width: 500px;
  overflow: hidden;
}

.menu-header {
  background: var(--header-bg);
  padding: 10px 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.category-tag {
  color: var(--category-color);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
}

.dietary-badge {
  font-size: 11px;
  font-weight: 800;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.dietary-badge.vegan {
  background: var(--vegan-bg);
  color: var(--vegan-text);
}

.menu-body {
  padding: 16px;
  display: flex;
  gap: 16px;
  align-items: flex-start;
}

.item-info {
  flex: 1;
}

.item-name {
  font-size: 20px;
  font-weight: 800;
  color: var(--item-name-color);
  margin: 0 0 8px 0;
  line-height: 1.2;
}

.item-desc {
  font-size: 13px;
  color: var(--desc-color);
  line-height: 1.6;
  margin: 0 0 12px 0;
}

.item-meta {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.meta-pill {
  background: var(--meta-pill-bg);
  color: var(--meta-pill-color);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}

.item-side {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}

.item-image-placeholder {
  width: 110px;
  height: 90px;
  background: var(--image-bg);
  border-radius: 12px;
  border: 2px solid var(--image-accent);
}

.price-row {
  display: flex;
  align-items: center;
  gap: 8px;
  width: 100%;
  justify-content: space-between;
}

.price {
  font-size: 18px;
  font-weight: 800;
  color: var(--price-color);
}

.add-btn {
  background: var(--btn-bg);
  color: var(--btn-text);
  border: none;
  border-radius: var(--btn-radius);
  padding: 6px 12px;
  font-size: 13px;
  font-weight: 700;
  cursor: pointer;
}

.menu-footer {
  background: var(--footer-bg);
  border-top: 1.5px solid var(--footer-border);
  padding: 10px 16px;
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.footer-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--footer-label-color);
  margin-right: 2px;
}

.pairing-chip {
  background: var(--chip-bg);
  color: var(--chip-color);
  font-size: 12px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
}
